// Format recent conversation history
const inputData = $input.all();
let rows = inputData.map(item => item.json);

rows.sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
rows = rows.slice(0, 5);

let formattedText = '';
rows.forEach((row, index) => {
  formattedText += `registro${index + 1}:
- agent: ${row.agent_name || 'Unknown'}
- user: ${row.message_user}
- assistant: ${row.message_ai}
- date: ${row.created_at}

`;
});

return [{
  json: {
    formatted_memories: formattedText.trim()
  }
}];

// Format Zep graph search results
const inputData = $input.all();
let factsText = '';

for (const item of inputData) {
  try {
    if (!item.json.data) continue;
    const parsedData = JSON.parse(item.json.data);
    if (!parsedData.edges || parsedData.edges.length === 0) continue;

    const facts = parsedData.edges.map(edge => edge.fact || '');
    const formattedFacts = facts
      .map((fact, index) => `fact${index + 1}: ${fact}`)
      .join(' ');

    factsText += formattedFacts + ' ';
  } catch (error) {
    console.error('Error parsing Zep data:', error);
    continue;
  }
}

return [{
  json: {
    facts_text: factsText.trim()
  }
}];

